              src="/Foto1.HEIC"
              alt="Imagen 2"
            />
            <img
              className="rounded-lg absolute left-16 transition-transform transform hover:scale-110"
              width={150}
              height={150}
              style={{ top: 'calc(85%)' }}
              src="/Foto4.HEIC"
              alt="Imagen 2"
            />
          </div> */}
          <div className="ml-40 relative">
            <img
              className="rounded-lg transition-transform transform hover:scale-110"
              width={300}
              height={250}
              src="/Foto3.HEIC"
              alt="Imagen 1"
            />
            <img
