              style={image2Position}
              src="/Foto1.HEIC"
              alt="Imagen 2"
            />
            <img
              className="rounded-lg absolute transition-transform transform hover:scale-110 moving-image"
              width={150}
              height={150}
              style={image3Position}
              src="/Foto4.HEIC"
              alt="Imagen 2"
            />
          </div>
        </div>
        {/* Text center */}
        <div className="h-full flex flex-col justify-center items-center gap-5">
          <h3 className="text-[#6d7561] md:text-2xl font-medium text-center">
            ¡Los invitamos a festejar nuestra boda!
          </h3>
          <h1 className="text-[#6d7561] text-4xl md:text-4xl font-bold text-center">
            Anto & Kevin
          </h1>
          <a
